import{c as a,Q as t,j as d,m as o}from"./chunks/framework.DVkeSyfh.js";const m=JSON.parse('{"title":"Семейства анализа","description":"","frontmatter":{},"headers":[],"relativePath":"ru/analysis.md","filePath":"ru/analysis.md","lastUpdated":1780001723000}'),s={name:"ru/analysis.md"};function i(c,e,l,n,p,r){return t(),d("div",null,[...e[0]||(e[0]=[o('<h1 id="семеиства-анализа" tabindex="-1">Семейства анализа <a class="header-anchor" href="#семеиства-анализа" aria-label="Permalink to &quot;Семейства анализа&quot;">​</a></h1><p>Эта страница описывает результаты анализа, используемые основным приложением. Используйте её, чтобы решить, какой анализ запускать, прежде чем тратить время CPU или GPU. Об отдельном инструменте разметки и обучения классификаторов см. <a href="./rhythm-lab.html">Rhythm Lab</a>.</p><h2 id="семеиства-анализа-1" tabindex="-1">Семейства анализа <a class="header-anchor" href="#семеиства-анализа-1" aria-label="Permalink to &quot;Семейства анализа&quot;">​</a></h2><p>Каждое семейство записывает свои данные в SQLite и поддерживает свой рабочий процесс:</p><table tabindex="0"><thead><tr><th>Семейство</th><th>Что делает</th><th>Когда использовать</th></tr></thead><tbody><tr><td>Sonara</td><td>Извлекает объяснимые признаки плейлиста: темп, энергию, громкость, ритм и тональные сводки.</td><td>Нужен быстрый поиск по seed-треку, видимые регуляторы признаков или фильтры библиотеки.</td></tr><tr><td>MAEST</td><td>Предсказывает жанровые метки и сохраняет MAEST embeddings.</td><td>Нужны сгенерированные жанровые теги, проверка жанров, preset <code>syncopated</code> или входные данные для классификатора.</td></tr><tr><td>MERT</td><td>Строит audio embeddings для поиска похожих по seed-треку.</td><td>Нужно поведение «найти треки, близкие к этому треку» на основе аудиомодели.</td></tr><tr><td>CLAP</td><td>Строит музыкальные audio embeddings и текстовые векторы.</td><td>Нужен поиск «текст в аудио» по описательным запросам.</td></tr><tr><td>Продвинутые классификаторы</td><td>Оценивает треки локальной моделью, обученной в Rhythm Lab.</td><td>Нужен переиспользуемый пользовательский сигнал, например наличие вокала, живые инструменты или другая метка конкретного профиля.</td></tr></tbody></table><h3 id="sonara" tabindex="-1">Sonara <a class="header-anchor" href="#sonara" aria-label="Permalink to &quot;Sonara&quot;">​</a></h3><p>Sonara используется в режиме плейлиста как быстрый объяснимый проход по признакам. Она сохраняет компактный набор признаков плейлиста в <code>metadata_json.sonara_features</code>, а имя модели — в <code>metadata_json.sonara_model</code>.</p><p>Сохраняемые группы и ключи:</p><ul><li>Core features: <code>bpm</code>, <code>beats</code>, <code>onset_frames</code>, <code>onset_density</code>, <code>n_beats</code>, <code>rms_mean</code>, <code>rms_max</code>, <code>loudness_lufs</code>, <code>dynamic_range_db</code>, <code>spectral_centroid_mean</code>, <code>zero_crossing_rate</code>, <code>duration_sec</code>.</li><li>Perceptual features: <code>energy</code>, <code>danceability</code>, <code>valence</code>, <code>acousticness</code>.</li><li>Musical key: <code>key</code>, <code>key_confidence</code>.</li><li>Tonal analysis: <code>predominant_chord</code>, <code>chord_change_rate</code>, <code>dissonance</code>.</li><li>Spectral features: <code>spectral_bandwidth_mean</code>, <code>spectral_rolloff_mean</code>, <code>spectral_flatness_mean</code>, <code>spectral_contrast_mean</code>, <code>mfcc_mean</code>, <code>chroma_mean</code>.</li></ul><p>BPM и <code>key</code> в Sonara — это проанализированные значения, а не копии тегов файла. Приложение хранит исходные данные ключа Sonara и не выводит из них нотацию Camelot.</p><p>CLI и UI вызывают Sonara с <code>batch_size</code> как числом параллельных рабочих процессов по трекам, а не как размером батча инференса нейросети.</p><p>Запускайте Sonara в первую очередь, если не уверены, с чего начать. Это самое прозрачное семейство анализа, потому что UI может напрямую показывать и смешивать его группы признаков.</p><h3 id="maest" tabindex="-1">MAEST <a class="header-anchor" href="#maest" aria-label="Permalink to &quot;MAEST&quot;">​</a></h3><p>Во время анализа MAEST записывает жанровые метаданные и embeddings только в SQLite:</p><ul><li><code>metadata_json.maest_model</code></li><li><code>metadata_json.maest_genres</code></li><li><code>metadata_json.maest_syncopated_rhythm</code></li><li><code>embeddings.embedding_key = &quot;maest&quot;</code></li></ul><p>Адаптер использует <code>maest-infer</code> с <code>discogs-maest-30s-pw-129e-519l</code>. Он анализирует до трёх 30-секундных окон на трек:</p><ul><li>окно со смещением 60 секунд;</li><li>окно около 38 процентов длительности;</li><li>окно около 72 процентов длительности.</li></ul><p>Невозможные или совпадающие окна ограничиваются по диапазону и дедуплицируются. Активации по каждой метке усредняются по окнам, после чего сохраняются метки с наибольшими значениями. Строки MAEST embedding усредняются по тем же окнам и сохраняются под embedding key <code>maest</code>.</p><p>Сам анализ MAEST не изменяет аудиофайлы. Отдельное действие сохранения жанров позже может записать сохранённые метки MAEST в стандартные жанровые теги аудио. Флаг <code>maest_syncopated_rhythm</code> выводится из сохранённых жанров MAEST и используется preset <code>syncopated</code> библиотеки.</p><p>Запускайте MAEST перед записью жанров или использованием preset <code>syncopated</code>. Проверяйте метки перед записью в файлы: анализ работает только с базой данных, а запись тегов — это явное изменение аудиофайлов.</p><h3 id="mert" tabindex="-1">MERT <a class="header-anchor" href="#mert" aria-label="Permalink to &quot;MERT&quot;">​</a></h3><p>MERT строит audio-to-audio embeddings под embedding key <code>mert</code>.</p><p>Модель по умолчанию:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>m-a-p/MERT-v1-95M</span></span></code></pre></div><p>Поиск MERT использует только векторы MERT. Он не смешивается с признаками Sonara или векторами CLAP.</p><p>Запускайте MERT, когда похожесть по seed-треку важнее объяснимых регуляторов. Результаты поиска зависят от существующих MERT embeddings, поэтому новопросканированные треки нужно проанализировать, прежде чем они появятся в полезных результатах MERT.</p><h3 id="clap" tabindex="-1">CLAP <a class="header-anchor" href="#clap" aria-label="Permalink to &quot;CLAP&quot;">​</a></h3><p>CLAP строит музыкальные audio embeddings под embedding key <code>clap</code> и создаёт текстовые векторы для поиска «текст в аудио».</p><p>Активный чекпойнт:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>lukewys/laion_clap/music_audioset_epoch_15_esc_90.14.pt</span></span></code></pre></div><p>Текстовый поиск требует CLAP audio embeddings, созданных тем же чекпойнтом CLAP.</p><p>Запускайте CLAP, когда нужно искать по настроению, инструментовке, энергии или другому описательному языку. Понятные конкретные запросы обычно работают лучше, чем отдельные жанровые слова.</p><h3 id="продвинутые-классификаторы" tabindex="-1">Продвинутые классификаторы <a class="header-anchor" href="#продвинутые-классификаторы" aria-label="Permalink to &quot;Продвинутые классификаторы&quot;">​</a></h3><p>Продвинутые классификаторы — это локальные профили классификаторов, а не модели аудиоанализа, которые сами декодируют файлы. Они оценивают треки по уже сохранённым результатам анализа:</p><ul><li>признаки плейлиста SONARA из <code>metadata_json.sonara_features</code>;</li><li>MERT embeddings из <code>embeddings.embedding_key = &quot;mert&quot;</code>;</li><li>MAEST embeddings из <code>embeddings.embedding_key = &quot;maest&quot;</code>.</li></ul><p>Треки, у которых отсутствует любой из этих входных данных, пропускаются задачей классификатора. Оценки сохраняются в <code>track_classifier_scores</code> под <code>classifier_key</code> профиля.</p><p>Используйте продвинутые классификаторы после того, как обучите и продвинете профиль в Rhythm Lab. Они лучше всего подходят для персональных представлений о библиотеке, которые трудно выразить обобщённой жанровой меткой или одним seed-треком похожести.</p><p>Стабильные расположения моделей используют artifact prefix профиля:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>models/classifiers/&lt;artifact-prefix&gt;/model.joblib</span></span></code></pre></div><p>Эти файлы создаются вне основного приложения командой promotion из Rhythm Lab:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.\\.venv\\Scripts\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">python.exe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> tools\\rhythm</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">lab\\rhythm_lab_cli.py promote </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">profile live_instrumentation</span></span></code></pre></div><p>Продвинутые файлы <code>model.joblib</code> и <code>model.json</code> — это локальные артефакты, игнорируемые git. Исходные обучающие артефакты Rhythm Lab остаются в рабочей области лаборатории для конкретного классификатора:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>tools/rhythm-lab/artifacts/&lt;artifact-prefix&gt;/</span></span></code></pre></div><p>Продвинутые метаданные генерируются из профиля Rhythm Lab и артефакта модели: <code>classifier_key</code>, profile name, profile type, labels, feature set, исходный артефакт и количества обучающих меток. Обучающие метрики Rhythm Lab используют единую нейтральную к профилю структуру для всех профилей (метрики <code>positive_*</code> и <code>label_order</code>) вместо специфичных для классификатора псевдонимов метрик.</p><p>Об управлении профилями, разметке, обучении, предсказании, promotion, архивировании и удалении в Rhythm Lab см. <a href="./rhythm-lab.html">Rhythm Lab</a>.</p><p>Видимая пользователю оценка — это вероятность классификатора для положительной обучающей метки профиля. Поскольку UI может округлять вероятности, значение, показанное как <code>1.0000</code>, может быть немного ниже математической <code>1.0</code>. Для практической фильтрации используйте пороги вроде <code>0.99</code>, <code>0.95</code> или <code>0.90</code>, а не точную <code>1.0</code>.</p>',46)])])}const b=a(s,[["render",i]]);export{m as __pageData,b as default};
